 85	/* rlc_data_req queue - begin                                               */
 86	/****************************************************************************/
 87	
 88	
 89	#include <pthread.h>
 90	
 91	/* NR PDCP and RLC both use "big locks". In some cases a thread may do
 92	 * lock(rlc) followed by lock(pdcp) (typically when running 'rx_sdu').
 93	 * Another thread may first do lock(pdcp) and then lock(rlc) (typically
 94	 * the GTP module calls 'nr_pdcp_data_req' that, in a previous implementation
 95	 * was indirectly calling 'rlc_data_req' which does lock(rlc)).
 96	 * To avoid the resulting deadlock it is enough to ensure that a call
 97	 * to lock(pdcp) will never be followed by a call to lock(rlc). So,
 98	 * here we chose to have a separate thread that deals with rlc_data_req,
 99	 * out of the PDCP lock. Other solutions may be possible.
100	 * So instead of calling 'rlc_data_req' directly we have a queue and a
101	 * separate thread emptying it.
102	 */
103	
104	typedef struct {
105	  protocol_ctxt_t ctxt_pP;
106	  srb_flag_t      srb_flagP;
107	  MBMS_flag_t     MBMS_flagP;
108	  rb_id_t         rb_idP;
109	  mui_t           muiP;
110	  confirm_t       confirmP;
111	  sdu_size_t      sdu_sizeP;
112	  uint8_t *sdu_pP;
113	} rlc_data_req_queue_item;
114	
115	#define RLC_DATA_REQ_QUEUE_SIZE 10000
116	
117	typedef struct {
118	  rlc_data_req_queue_item q[RLC_DATA_REQ_QUEUE_SIZE];
119	  volatile int start;
120	  volatile int length;
121	  pthread_mutex_t m;
122	  pthread_cond_t c;
123	} rlc_data_req_queue;
124	
125	static rlc_data_req_queue q;
126	
127	static void *rlc_data_req_thread(void *_)
128	{
129	  int i;
130	
131	  pthread_setname_np(pthread_self(), "RLC queue");
132	  while (1) {
133	    if (pthread_mutex_lock(&q.m) != 0) abort();
134	    while (q.length == 0)
135	      if (pthread_cond_wait(&q.c, &q.m) != 0) abort();
136	    i = q.start;
137	    if (pthread_mutex_unlock(&q.m) != 0) abort();
138	
139	    rlc_data_req(&q.q[i].ctxt_pP,
140	                 q.q[i].srb_flagP,
141	                 q.q[i].MBMS_flagP,
142	                 q.q[i].rb_idP,
143	                 q.q[i].muiP,
144	                 q.q[i].confirmP,
145	                 q.q[i].sdu_sizeP,
146	                 q.q[i].sdu_pP,
147	                 NULL,
148	                 NULL);
149	
150	    if (pthread_mutex_lock(&q.m) != 0) abort();
151	
152	    q.length--;
153	    q.start = (q.start + 1) % RLC_DATA_REQ_QUEUE_SIZE;
154	
155	    if (pthread_cond_signal(&q.c) != 0) abort();
156	    if (pthread_mutex_unlock(&q.m) != 0) abort();
157	  }
158	}
159	
160	static void init_nr_rlc_data_req_queue(void)
161	{
162	  pthread_t t;
163	
164	  pthread_mutex_init(&q.m, NULL);
165	  pthread_cond_init(&q.c, NULL);
166	
167	  if (pthread_create(&t, NULL, rlc_data_req_thread, NULL) != 0) {
168	    LOG_E(PDCP, "%s:%d:%s: fatal\n", __FILE__, __LINE__, __FUNCTION__);
169	    exit(1);
170	  }
171	}
172	
173	static void enqueue_rlc_data_req(const protocol_ctxt_t *const ctxt_pP,
174	                                 const srb_flag_t srb_flagP,
175	                                 const MBMS_flag_t MBMS_flagP,
176	                                 const rb_id_t rb_idP,
177	                                 const mui_t muiP,
178	                                 confirm_t confirmP,
179	                                 sdu_size_t sdu_sizeP,
180	                                 uint8_t *sdu_pP)
181	{
182	  int i;
183	  int logged = 0;
184	
185	  if (pthread_mutex_lock(&q.m) != 0) abort();
186	  while (q.length == RLC_DATA_REQ_QUEUE_SIZE) {
187	    if (!logged) {
188	      logged = 1;
189	      LOG_W(PDCP, "%s: rlc_data_req queue is full\n", __FUNCTION__);
190	    }
191	    if (pthread_cond_wait(&q.c, &q.m) != 0) abort();
192	  }
193	
194	  i = (q.start + q.length) % RLC_DATA_REQ_QUEUE_SIZE;
195	  q.length++;
196	
197	  q.q[i].ctxt_pP    = *ctxt_pP;
198	  q.q[i].srb_flagP  = srb_flagP;
199	  q.q[i].MBMS_flagP = MBMS_flagP;
200	  q.q[i].rb_idP     = rb_idP;

  q.q[i].rb_idP     = rb_idP;
  q.q[i].muiP       = muiP;
  q.q[i].confirmP   = confirmP;
  q.q[i].sdu_sizeP  = sdu_sizeP;
  q.q[i].sdu_pP     = sdu_pP;

  if (pthread_cond_signal(&q.c) != 0) abort();
  if (pthread_mutex_unlock(&q.m) != 0) abort();
}

void du_rlc_data_req(const protocol_ctxt_t *const ctxt_pP,
                     const srb_flag_t srb_flagP,
                     const MBMS_flag_t MBMS_flagP,
                     const rb_id_t rb_idP,
                     const mui_t muiP,
                     confirm_t confirmP,
                     sdu_size_t sdu_sizeP,
                     uint8_t *sdu_pP)
{
  enqueue_rlc_data_req(ctxt_pP,
                       srb_flagP,
                       MBMS_flagP,
                       rb_idP, muiP,
                       confirmP,
                       sdu_sizeP,
                       sdu_pP);
}

